var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ARTHUR_ROOT_NPC_NULL","text":{"KOREA":"흐음…","JPN":"ふーん……","ENG":"Hmm...","TWN":"嗯…"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ARTHUR_ROOT_NPC_NULL","text":{"KOREA":"이 정도면 충분히 모았나?","JPN":"もう十分か？","ENG":"Will this be enough?","TWN":"這樣就足夠了嗎？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"또 혼자서 돌아다니던 거니?","JPN":"また一人で歩き回っていたのかしら。","ENG":"Have you been wandering alone again?","TWN":"…你又一個人到處亂跑嗎？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ARTHUR_ROOT_NPC_NULL","text":{"KOREA":"이제 막 돌아가려던 참입니다.","JPN":"今帰ろうとしていたところです。","ENG":"I was just making my way back.","TWN":"我正準備回去了。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ARTHUR_ROOT_NPC_NULL","text":{"KOREA":"유행병 치료제에 쓸 약초가 부족하다고 들어서요. 다들 손발이 바쁜 시기잖습니까?","JPN":"流行り病の治療剤に使う薬草が足りないと聞きましたので。みんな忙しい時期ではないですか。","ENG":"I heard there is a shortage of herbs used to treat the epidemic disease, and everyone is already so busy.","TWN":"聽說治療流行病的藥草不夠，大家都很忙吧？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"아무리 그래도 아발론의 왕이 산중에서 풀을 캐고 있다니.","JPN":"いくらなんでもアバロンの王が山の中で草を集めているなんて。","ENG":"Even if so, the king of Avalon is plucking herbs in the mountains?","TWN":"再怎麼說，阿瓦隆的王在山中一個人採摘草藥也太奇怪了。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"신하들이 알게 되면 또 까무러치겠네.","JPN":"臣下がそれを知るとまた仰天するわ。","ENG":"Your subjects will be horrified if they found out.","TWN":"如果臣子們知道了，又會嚇死吧？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ARTHUR_ROOT_NPC_NULL","text":{"KOREA":"왕이 백성을 만날 때에도 군대를 대동하라는 사람들이니까요.","JPN":"王が民に会う時にも軍隊を連れていけという人たちですから。","ENG":"As they summon the entire army when the king goes to meet his people.","TWN":"他們可是連王接見百姓都要帶上一整支軍隊的人。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ARTHUR_ROOT_NPC_NULL","text":{"KOREA":"아마 제 베갯머리에서 거미가 나와도, 성안의 온 경비를 소집할 겁니다.","JPN":"きっと私の枕からクモが出ても、城の中の警備を全員呼び集めるでしょう。","ENG":"They would even call upon all the guards within the castle if so much as a spider came out from my pillowcase.","TWN":"要是我的枕頭裡爬進了一隻蜘蛛，甚至也會把所有守衛都叫進來。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그런 과보호가 마냥 나쁜 건 아니야.","JPN":"でも過保護だからって悪いことばかりじゃないわ。","ENG":"Being overprotective is not always bad.","TWN":"這種過度保護也不全是壞事。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"사람의 앞길은 요정도 모르는 거잖니?","JPN":"人の未来なんて妖精にもわからないものよ。","ENG":"Not even a fairy knows what the future holds, no?","TWN":"就連精靈也不知道接下來發生的每件事吧？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ARTHUR_ROOT_NPC_NULL","text":{"KOREA":"하하, 미래를 보는 요정께서 그런 말씀을 하다니. 재밌네요.","JPN":"はは、未来を見る妖精さんにそう言われるとは。面白いですね。","ENG":"Haha, funny that the fairy with foresight would say such a thing.","TWN":"哈哈，能預見未來的精靈竟然這麼說。真有趣。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"농담이 아니야. 우리의 예언 중엔 아주 사소한 것이 계기가 되는 비극도 많으니까.","JPN":"冗談じゃないわ。アタシたちの予言の中には、とても些細なことがきっかけで起きる悲劇もあるんだから。","ENG":"I am not joking. Our prophecies tend to cause tragedies by even the smallest of things.","TWN":"這不是玩笑，我們的預言中有很多因小事而引發的悲劇。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ARTHUR_ROOT_NPC_NULL","text":{"KOREA":"하지만 그런 작은 사소한 계기가 비극을 막아낸 역사도 적지 않죠.","JPN":"ですが、そのような些細なきっかけが悲劇を防いだ歴史も少なくありません。","ENG":"But history has told of times when those insignificant moments also stopped tragedy.","TWN":"但也有不少因小小的契機而阻止了悲劇的歷史。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ARTHUR_ROOT_NPC_NULL","text":{"KOREA":"한낱 인간이 수 천 년의 역사를 아우르며 칭송받는 영웅의 이야기. 멋지지 않나요?","JPN":"一介の人間が数千年にわたり称えられる英雄になる話。素晴らしいとは思いませんか？","ENG":"A hero's tale of a mere human being praised for a thousand years. Isn't that wonderful?","TWN":"一個普通人能夠跨越千年的歷史，被後世稱頌為英雄。不是很棒嗎？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"왕은 영웅이 되어선 안 돼.","JPN":"王は英雄になってはいけないの。","ENG":"A king must not become a hero.","TWN":"王不應該成為英雄。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그 호기로움과 정의로움이 결국 약점이 되어서 단명하고 말거든.","JPN":"その豪気と正義感が、結局は弱点になって早死にするのよ。","ENG":"Curiosity and righteousness will eventually become his weakness, leading to death.","TWN":"那種勇敢和正義最終會成為弱點，成為短命的理由。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ARTHUR_ROOT_NPC_NULL","text":{"KOREA":"그건 요정으로서 하는 예언인가요?","JPN":"それは妖精としての予言でしょうか？","ENG":"Is that a prophecy from you as a fairy?","TWN":"這是作為精靈的預言嗎？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"왕의 조언자로서 하는 충고야.","JPN":"王の助言者としての忠告よ。","ENG":"It is advice from your advisor.","TWN":"這是作為王的顧問的忠告。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ARTHUR_ROOT_NPC_NULL","text":{"KOREA":"그렇다면 새겨듣도록 하죠.","JPN":"ならば肝に銘じましょう。","ENG":"Then I will keep it to heart.","TWN":"那麼，我會銘記在心。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ARTHUR_ROOT_NPC_NULL","text":{"KOREA":"현명한 왕이 되려면 솔직한 스승이 필요한 법이니까요.","JPN":"賢明な王になるためには、正直者の師匠が必要ですから。","ENG":"A wise king requires an honest teacher.","TWN":"一個明智的王身邊，總是會有一個坦誠的導師。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그냥 현명한 왕이 되게 해달라고 소원을 빌어보는 건 어때?","JPN":"いっそ賢明な王になれますようにと願うのはどうかしら。","ENG":"How about just wishing to become a wise king?","TWN":"要想成為明智的君王，為什麼你不許願這麼做呢？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L32_1","type":"dialog","speaker":"ARTHUR_ROOT_NPC_NULL","text":{"KOREA":"아발론의 왕은 평생에 한 번 요정에게 소원을 빌 수 있다고 하죠.","JPN":"アバロンの王は一生に一度だけ妖精に願いを叶えてもらえるそうですね。","ENG":"The king of Avalon is said to be given one wish during his lifetime.","TWN":"據說阿瓦隆的王一生只能向精靈許一個願望。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"ARTHUR_ROOT_NPC_NULL","text":{"KOREA":"하지만 자신만을 위해 소원을 비는 것은 금기입니다.","JPN":"しかし、自分のために願うのは禁忌です。","ENG":"However, wishing something for myself is forbidden.","TWN":"但為自己許願是禁忌。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그래? 지금까지의 왕들은 나를 위하는 것이 곧 대국적인 일이라면서 잘만 포장하던데.","JPN":"そう？　今までの王は、自分のために願うことが世のためになるって、もっともらしく言っていたけれど。","ENG":"Is that so? Those before you have always seemed to find a way to present it to me as if it were something of national importance.","TWN":"是嗎？到目前為止的王都假借著國家的名義，為自己許下了願望，並且他們包裝得很好。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L36_1","type":"dialog","speaker":"ARTHUR_ROOT_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"ARTHUR_ROOT_NPC_NULL","text":{"KOREA":"어쩌면 제가 틀렸을지도 모르죠. 신념이란 명목으로 오기를 부리는 걸 수도 있고요.","JPN":"もしかしたら私が間違っているのかもしれません。信念という名目で、意地を張っているだけなのかも。","ENG":"Maybe I am in the wrong. Or I may be acting arrogantly in the name of faith.","TWN":"也許我錯了，也許這是我以信念為名的固執。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};